    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    hexi::deserializer des(buffer);
    NetworkPacket packet;

    // Read the packet_id
    des.read(packet.packet_id);

    // Read the username using the length prefix
    des.read(hexi::prefixed<uint32_t>(packet.username));

    // Read the score count, then use read_container to read the scores vector
    uint32_t score_count;
    des.read(score_count);
    des.read_container(packet.scores, score_count);

    // Read the metadata string as null-terminated for zero-copy
    des.read(hexi::null_terminated(packet.metadata));

    // Skip any remaining padding bytes (if any)
    if (des.remaining() > 0) {
        des.skip(des.remaining());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

