const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer for reading
    return buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to the end of current data (where next write should occur)
    return buffer.data() + buffer.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    // Calculate readable bytes and available free space in the buffer
    BufferInfo info;
    info.readable_size = buffer.size();           // Current data size (readable bytes)
    info.free_space = buffer.capacity() - buffer.size();  // Space available without reallocation
    return info;
}
```

