template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block allocator for int32_t with element_count blocks
    // Initially, all blocks are in the free list
    hexi::block_allocator<int32_t, element_count> allocator;

    std::cout << "=== Block Allocator Free List Management Demo ===\n";
    std::cout << "Free list uses LIFO (stack) with push()/pop() operations\n\n";

    // Track allocated blocks
    std::vector<int32_t*> allocated_blocks;

    // ===== PHASE 1: Demonstrate pop() behavior =====
    // allocate() internally calls pop() to remove from free list head
    std::cout << "PHASE 1: Allocating blocks (internally uses pop())\n";
    std::cout << "------------------------------------------------\n";
    for (size_t i = 0; i < 5; ++i) {
        int32_t* block = allocator.allocate(1);
        allocated_blocks.push_back(block);
        std::cout << "  Allocated block " << i << " at: " << block << "\n";
    }
    std::cout << "Free list now has " << (element_count - 5) << " blocks remaining\n\n";

    // ===== PHASE 2: Demonstrate push() behavior =====
    // deallocate() internally calls push() to add to free list head
    std::cout << "PHASE 2: Deallocating blocks (internally uses push())\n";
    std::cout << "----------------------------------------------------\n";
    std::cout << "Deallocating blocks 0, 1, 2 in that order:\n";

    std::vector<int32_t*> deallocated_ptrs;
    for (size_t i = 0; i < 3; ++i) {
        std::cout << "  Deallocating block " << i << ": " << allocated_blocks[i] 
                  << " -> push() to free list head\n";
        deallocated_ptrs.push_back(allocated_blocks[i]);
        allocator.deallocate(allocated_blocks[i], 1);
    }
    std::cout << "\nFree list state (head to tail): ";
    std::cout << "Block2 -> Block1 -> Block0 -> (other blocks)\n\n";

    // ===== PHASE 3: Demonstrate LIFO behavior =====
    // Since push() adds to head and pop() removes from head, we get LIFO
    std::cout << "PHASE 3: Reallocating to verify LIFO (Last-In-First-Out)\n";
    std::cout << "---------------------------------------------------------\n";
    std::cout << "Expected: Block2, Block1, Block0 (reverse of deallocation)\n\n";

    for (size_t i = 0; i < 3; ++i) {
        int32_t* block = allocator.allocate(1);  // Internally calls pop()
        std::cout << "  Allocation " << i << " returned: " << block;

        // Verify LIFO: should get blocks in reverse order of deallocation
        size_t expected_idx = 2 - i;  // 2, 1, 0
        if (block == deallocated_ptrs[expected_idx]) {
            std::cout << " ✓ Correct! (was " << (i == 0 ? "last" : 
                         i == 1 ? "second" : "first") << " deallocated)\n";
        } else {
            std::cout << " ✗ Unexpected address\n";
        }

        allocated_blocks[i] = block;
    }

    // ===== PHASE 4: Demonstrate free list state =====
    std::cout << "\nPHASE 4: Understanding free list structure\n";
    std::cout << "-------------------------------------------\n";
    std::cout << "The free list is a singly-linked list:\n";
    std::cout << "  - push() adds to HEAD (O(1) operation)\n";
    std::cout << "  - pop() removes from HEAD (O(1) operation)\n";
    std::cout << "  - This creates LIFO/stack behavior\n";
    std::cout << "  - Each free block stores pointer to next free block\n\n";

    // Cleanup
    std::cout << "Cleanup: Deallocating all remaining blocks...\n";
    for (auto* block : allocated_blocks) {
        if (block) {
            allocator.deallocate(block, 1);
        }
    }

    std::cout << "\n=== Demo Complete ===\n";
    std::cout << "All blocks returned to free list via push() operations\n";
}
```

## Key Points Demonstrated:

1. **`pop()` behavior**: When you call `allocate()`, it internally uses `pop()` to remove a block from the head of the free list.

2. **`push()` behavior**: When you call `deallocate()`, it internally uses `push()` to add the block back to the head of the free list.

3. **LIFO structure**: The free list behaves as a stack (Last-In-First-Out) because both operations work on the head of the list.

4. **Efficiency**: Both operations are O(1) because they only manipulate the head pointer.

5. **Internal structure**: Each free block contains a pointer to the next free block, forming a singly-linked list.

