# Complete Implementation

Here's the complete implementation of the varint encoding and decoding functions using the Hexi library:

```cpp
#include <hexi/shared.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <vector>
#include <cstdint>
#include <type_traits>

using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned type for proper bit operations
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT uvalue = static_cast<UnsignedT>(value);

    // Encode using 7 bits per byte, with MSB as continuation flag
    do {
        uint8_t byte = static_cast<uint8_t>(uvalue & 0x7F);  // Get lower 7 bits
        uvalue >>= 7;  // Shift right by 7 bits

        // Set continuation bit if more bytes follow
        if (uvalue != 0) {
            byte |= 0x80;
        }

        writer.write(byte);
        bytes_written++;
    } while (uvalue != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using UnsignedT = typename std::make_unsigned<T>::type;
    UnsignedT result = 0;
    int shift = 0;

    // Decode varint byte by byte
    while (true) {
        uint8_t byte = reader.read<uint8_t>();

        // Extract the lower 7 bits and add to result at appropriate position
        result |= static_cast<UnsignedT>(byte & 0x7F) << shift;

        // Check continuation bit (MSB)
        if ((byte & 0x80) == 0) {
            break;  // No continuation bit, this is the last byte
        }

        shift += 7;
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
    {
        hexi::pmc::binary_stream_writer writer(adaptor);
        encode_varint(writer, original_value);
    }

    // Decode the value
    {
        hexi::pmc::binary_stream_reader reader(adaptor);
        T decoded_value = decode_varint<T>(reader);

        // Verify roundtrip correctness
        return original_value == decoded_value;
    }
}
```

## Explanation:

1. **`encode_varint`**: 
   - Converts the value to unsigned to handle bit operations correctly
   - Encodes 7 bits per byte, using the MSB (bit 7) as a continuation flag
   - Continues writing bytes while there are remaining bits to encode
   - Returns the number of bytes written

2. **`decode_varint`**:
   - Reads bytes one at a time from the reader
   - Extracts 7 bits of data from each byte
   - Combines them using bit shifting and OR operations
   - Stops when a byte without the continuation bit is encountered
   - Returns the decoded value cast to the requested type

3. **`encode_decode_roundtrip`**:
   - Creates a buffer and adaptor for I/O operations
   - Encodes the original value using a writer
   - Decodes it back using a reader
   - Compares the decoded value with the original to verify correctness

