using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    // Zero-length regions don't overlap
    if (src_len == 0 || dst_len == 0) {
        return false;
    }

    // Null pointers don't overlap (edge case)
    if (!src || !dst) {
        return false;
    }

    // Convert pointers to integer addresses for safe comparison
    const auto src_start = reinterpret_cast<std::uintptr_t>(src);
    const auto src_end = src_start + src_len;
    const auto dst_start = reinterpret_cast<std::uintptr_t>(dst);
    const auto dst_end = dst_start + dst_len;

    // Two regions overlap if:
    // - src starts before dst ends AND
    // - dst starts before src ends
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    // Nothing to copy is considered success
    if (length == 0) {
