    for (const auto& chunk : chunks) {
        total_size += chunk.size();
    }

    // Create a buffer to write to
    std::vector<uint8_t> buffer(total_size);

    // Create write adaptor
    hexi::pmc::buffer_write_adaptor writer(buffer.data(), buffer.size());

    // Write each chunk and track buffer state
    for (const auto& chunk : chunks) {
        // Check available space before each write
        if (writer.free() >= chunk.size()) {
            // Write the chunk
            writer.write(chunk.data(), chunk.size());
        }
    }

    // Return the total size written
    return writer.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create read adaptor
    hexi::pmc::buffer_read_adaptor reader(buffer.data(), buffer.size());

    // Result vector to store all read data
    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (reader.size() > 0) {
        // Determine how much to read (use size() to check remaining data)
        std::size_t to_read = std::min(chunk_size, reader.size());

        // Create temporary buffer for this partial read
        std::vector<uint8_t> temp(to_read);

        // Read the partial data
        reader.read(temp.data(), to_read);

        // Append to result
        result.insert(result.end(), temp.begin(), temp.end());
    }

    return result;
}

